INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RQ-0043','NR-1','Exposição à Poeira de Madeira','Químico','Partículas sólidas de corte/lixamento/aplainamento de madeira. Carcinógeno humano Grupo 1 (IARC) para madeira dura.','Rinite alérgica, asma ocupacional, câncer nasossinusal, dermatite de contato','NR-15, Anexo 13') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RQ-0044','NR-1','Exposição a Vapores de Tolueno','Químico','Solvente orgânico volátil em tintas, vernizes, colas e limpeza industrial.','Depressão do SNC, irritação de mucosas, dermatite, efeitos neurológicos/hepáticos crônicos','NR-15, Anexo 11, Quadro 1') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RQ-0045','NR-1','Exposição a Fumos Metálicos de Solda (Manganês)','Químico','Partículas metálicas geradas na fusão do eletrodo/arame durante soldagem (MIG/MAG, eletrodo revestido).','Manganismo, febre dos fumos metálicos, pneumoconiose (siderose), irritação respiratória aguda','NR-15, Anexo 11, Quadro 1') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RQ-0046','NR-1','Exposição ao Chumbo Inorgânico','Químico','Metal pesado de toxicidade sistêmica cumulativa — fundição, reciclagem de baterias, solda eletrônica.','Saturnismo, anemia, neuropatia periférica, efeitos reprodutivos','NR-15, Anexo 11, Quadro 1') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RQ-0047','NR-1','Exposição a Fibras de Amianto','Químico','Mineral fibroso em telhas/isolamentos antigos (proibido desde 2017). Risco em reforma/demolição de edificações anteriores.','Asbestose, mesotelioma pleural, câncer de pulmão (latência de 15-40 anos)','NR-15, Anexo 12; Lei 9.055/1995') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RF-0001','NR-1','Exposição a Ruído Contínuo ou Intermitente','Físico','Pressão sonora medida em dB(A), circuito SLOW. Acima de 115 dB(A) sem proteção: risco grave e iminente.','PAIR irreversível, zumbido, estresse, hipertensão','NR-15, Anexo 1') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RF-0002','NR-1','Exposição a Ruído de Impacto','Físico','Ruído de curta duração e alta intensidade (batidas, prensagem, martelamento).','PAIR de instalação súbita (trauma acústico), perfuração timpânica em exposições extremas','NR-15, Anexo 2') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RF-0003','NR-1','Exposição Ocupacional ao Calor','Físico','Avaliado pelo IBUTG — fundições, cozinhas industriais, trabalho externo em construção civil.','Desidratação, exaustão pelo calor, intermação (golpe de calor), cãibras','NR-15, Anexo 3') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RF-0004','NR-1','Exposição à Vibração em Mãos e Braços','Físico','Vibração transmitida ao sistema mão-braço por ferramentas manuais motorizadas.','Síndrome de Raynaud Ocupacional (dedo branco), distúrbios neurológicos e osteoarticulares','NR-15, Anexo 8') ON CONFLICT (id) DO NOTHING;
INSERT INTO perigos (id, norma, nome, categoria, descricao, consequencias, base_legal) VALUES ('RF-0005','NR-1','Exposição à Radiação Não-Ionizante (arco elétrico de soldagem)','Físico','Radiação UV/IV emitida pelo arco elétrico durante soldagem — ocorre junto com RQ-0045 na mesma atividade.','Ceratoconjuntivite actínica (vista de arco), queimaduras de pele','NR-15, Anexo 7') ON CONFLICT (id) DO NOTHING;
